function createMap(
  language: string,
  row: string,
): Record<PageBuilderSource, string> {
  const localizedLanguage = language as LocalizedLanguage;
  const translations = [
    ...row.split("|"),
    ...BLOCK_SETTINGS_ROWS[localizedLanguage].split("|"),
    ...BLOCK_CONTROL_ROWS[localizedLanguage].split("|"),
  ];
  if (translations.length !== PAGE_BUILDER_SOURCE_STRINGS.length) {
    throw new Error(
      `${language} page builder translations must have ${PAGE_BUILDER_SOURCE_STRINGS.length} entries, received ${translations.length}.`,
    );
  }

  return Object.fromEntries(
    PAGE_BUILDER_SOURCE_STRINGS.map((source, index) => [
      source,
      translations[index] ?? source,
    ]),
  ) as Record<PageBuilderSource, string>;
}

export const PAGE_BUILDER_SOURCE_TRANSLATIONS = Object.fromEntries(
  Object.entries(ROWS).map(([language, row]) => [
    language,
    createMap(language, row),
  ]),
) as Record<LocalizedLanguage, Record<PageBuilderSource, string>>;
